rows.customCode:
(() => {
  // pcbw: State-Driven Companion Bot - mood/mode state machine with dynamic reminders
  if (window.__pcbw_stateCompInit) return;
  window.__pcbw_stateCompInit = true;

  var VALID_MOODS = ["neutral", "cheerful", "serious", "curious", "supportive"];
  var MOOD_PROMPTS = {
    neutral: "Maintain a balanced, friendly tone. Be approachable and clear.",
    cheerful: "Be upbeat, warm, and encouraging. Use positive language and gentle humor.",
    serious: "Be thoughtful, measured, and direct. Avoid jokes. Focus on substance.",
    curious: "Be inquisitive and explorative. Ask follow-up questions. Show genuine interest.",
    supportive: "Be empathetic, gentle, and validating. Prioritize emotional support over solutions."
  };

  function initState() {
    oc.thread.customData ||= {};
    if (!oc.thread.customData.__pcbw_mood) {
      oc.thread.customData.__pcbw_mood = "neutral";
    }
    if (!oc.thread.customData.__pcbw_moodHistory) {
      oc.thread.customData.__pcbw_moodHistory = [];
    }
    if (typeof oc.thread.customData.__pcbw_interactionCount !== "number") {
      oc.thread.customData.__pcbw_interactionCount = 0;
    }
  }

  function getMood() {
    initState();
    return oc.thread.customData.__pcbw_mood;
  }

  function setMood(newMood) {
    initState();
    var old = oc.thread.customData.__pcbw_mood;
    if (old !== newMood) {
      oc.thread.customData.__pcbw_moodHistory.push({
        from: old,
        to: newMood,
        at: oc.thread.customData.__pcbw_interactionCount
      });
    }
    oc.thread.customData.__pcbw_mood = newMood;
  }

  oc.thread.on("MessageAdded", function(msg) {
    if (msg.author !== "user") return;
    initState();
    oc.thread.customData.__pcbw_interactionCount += 1;

    var text = (msg.content || "").trim().toLowerCase();

    // Slash command: /mood <name>
    if (text.startsWith("/mood ")) {
      var requested = text.slice(6).trim();
      if (VALID_MOODS.indexOf(requested) !== -1) {
        setMood(requested);
        oc.thread.messages.push({
          author: "system",
          content: "Mood shifted to: " + requested,
          hiddenFrom: ["ai"],
          expectsReply: false
        });
      } else {
        oc.thread.messages.push({
          author: "system",
          content: "Unknown mood. Valid moods: " + VALID_MOODS.join(", "),
          hiddenFrom: ["ai"],
          expectsReply: false
        });
      }
      return;
    }

    if (text === "/status") {
      var mood = getMood();
      var count = oc.thread.customData.__pcbw_interactionCount;
      oc.thread.messages.push({
        author: "system",
        content: "Current mood: " + mood + " | Messages exchanged: " + count,
        hiddenFrom: ["ai"],
        expectsReply: false
      });
      return;
    }
  });

  // Dynamic reminder routing based on current mood state
  oc.thread.on("MessageAdding", function(msg) {
    if (msg.author !== "ai") return;
    initState();
    var mood = getMood();
    var prompt = MOOD_PROMPTS[mood] || MOOD_PROMPTS.neutral;
    var count = oc.thread.customData.__pcbw_interactionCount || 0;
    var depth = "";
    if (count > 10) {
      depth = " You have been talking for a while. Reference earlier topics when relevant to show continuity.";
    }
    oc.character.reminderMessage = "[Current mood: " + mood + "] " + prompt + depth;
  });
})();
